import json
import re
from openai import AsyncOpenAI
from app.interfaces.llm_provider import AbstractLLMProvider
from app.config import settings

OPENROUTER_BASE_URL = "https://openrouter.ai/api/v1"


def _extract_json(text: str) -> dict:
    """Strip markdown code fences and parse JSON from response text."""
    # Remove ```json ... ``` or ``` ... ``` fences
    text = re.sub(r"```(?:json)?\s*", "", text)
    text = text.replace("```", "").strip()
    # Find the outermost JSON object
    start = text.find("{")
    end = text.rfind("}") + 1
    if start == -1 or end == 0:
        raise ValueError(f"No JSON object found in response: {text!r}")
    return json.loads(text[start:end])


class OpenRouterProvider(AbstractLLMProvider):
    def __init__(self, api_key: str | None = None):
        self._api_key = api_key
        self._client: AsyncOpenAI | None = None

    @property
    def client(self) -> AsyncOpenAI:
        if self._client is None:
            self._client = AsyncOpenAI(
                api_key=self._api_key or settings.OPENROUTER_API_KEY or None,
                base_url=OPENROUTER_BASE_URL,
            )
        return self._client

    async def chat_completion(
        self, messages: list[dict], system_prompt: str, model: str
    ) -> str:
        msgs = [{"role": "system", "content": system_prompt}] + messages
        response = await self.client.chat.completions.create(model=model, messages=msgs)
        return response.choices[0].message.content

    async def structured_completion(
        self, messages: list[dict], system_prompt: str, model: str
    ) -> dict:
        # OpenRouter free models don't support response_format=json_object,
        # so we ask for JSON in the prompt and parse manually.
        msgs = [
            {"role": "system", "content": system_prompt + "\n\nRespond with valid JSON only."}
        ] + messages
        response = await self.client.chat.completions.create(model=model, messages=msgs)
        return _extract_json(response.choices[0].message.content)
